import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess }) => {
  const [codeCli, setCodeCli] = useState('');
  const [codeArt, setCodeArt] = useState('');
  const [dateCom, setDateCom] = useState('');
  const [QteCom, setQteCom] = useState('');
  const [clients, setClients] = useState([]);
  const [articles, setArticles] = useState([]);

  useEffect(() => {
    if (selectedCommande) {
      setCodeCli(selectedCommande.codeCli || '');
      setCodeArt(selectedCommande.codeArt || '');
      setDateCom(selectedCommande.dateCom || '');
      setQteCom(selectedCommande.QteCom || '');
    } else {
      setCodeCli('');
      setCodeArt('');
      setDateCom('');
      setQteCom('');
    }
  }, [selectedCommande]);

  useEffect(() => {
    fetch('http://localhost:3001/clients')
      .then(res => res.json())
      .then(setClients)
      .catch(console.error);

    fetch('http://localhost:3001/articles')
      .then(res => res.json())
      .then(setArticles)
      .catch(console.error);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();

    const commande = { codeCli, codeArt, dateCom, QteCom };

    const method = selectedCommande ? 'PUT' : 'POST';
    const url = selectedCommande
      ? `http://localhost:3001/commandes/${selectedCommande.idCOM}`
      : 'http://localhost:3001/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(commande),
      });

      if (!res.ok) throw new Error(await res.text());
      onSuccess(); // recharge la liste
    } catch (err) {
      console.error('Erreur soumission commande :', err);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h3>{selectedCommande ? 'Modifier' : 'Ajouter'} une commande</h3>

      <label>Client:</label>
      <select value={codeCli} onChange={e => setCodeCli(e.target.value)} required>
        <option value="">-- Sélectionner un client --</option>
        {clients.map(c => (
          <option key={c.codeCli} value={c.codeCli}>
            {c.nomCli} {c.prenomCli}
          </option>
        ))}
      </select>

      <label>Article:</label>
      <select value={codeArt} onChange={e => setCodeArt(e.target.value)} required>
        <option value="">-- Sélectionner un article --</option>
        {articles.map(a => (
          <option key={a.codeArt} value={a.codeArt}>
            {a.nomArt}
          </option>
        ))}
      </select>

      <label>Date:</label>
      <input type="date" value={dateCom} onChange={e => setDateCom(e.target.value)} required />

      <label>Quantité:</label>
      <input type="number" value={QteCom} onChange={e => setQteCom(e.target.value)} required />

      <button type="submit">{selectedCommande ? 'Modifier' : 'Ajouter'}</button>
    </form>
  );
};

export default CommandeForm;
